\[
H(\beta) = \begin{pmatrix}
(t + g)\beta^{-1} + (t - g)\beta & -i\Delta(\beta^{-1} - \beta) \\
i\Delta(\beta^{-1} - \beta) & (t - g)\beta^{-1} + (t + g)\beta
\end{pmatrix}
\]

